#include<bits/stdc++.h>
using namespace std;
int n,m,a[1010][1010],f[1010][1010];
int dx[4]={0,0,1,-1},dy[4]={1,-1,0,0};
int fa[1000010],s[1000010],ans=0;
struct node
{
    int x,y,num;
    bool operator<(const node&b)const
    {
        return num<b.num;
    }
}b[1000010];
int find(int x)
{
    return(x==fa[x]?x:fa[x]=find(fa[x]));
}
void merge(int x,int y)
{
    int a=find(x),b=find(y);
    if(a!=b)
    {
        fa[a]=b;
        s[b]|=s[a];
    }
}
int id(int x,int y)
{
    return (x-1)*m+y;
}
int main()
{
    scanf("%d%d",&n,&m);
    memset(a,0x3f,sizeof(a));
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=m;j++)
        {
            scanf("%d",&a[i][j]);
            if(a[i][j]<0)
            {
                a[i][j]=(-a[i][j]);
            }
            else
            {
                f[i][j]=1;
            }
            b[id(i,j)]=(node){i,j,a[i][j]};
            fa[id(i,j)]=id(i,j);
        }
    }
    sort(b+1,b+1+id(n,m));
    for(int i=1;i<=n*m;i++)
    {
        for(int j=0;j<4;j++)
        {
            int xx=b[i].x+dx[j],yy=b[i].y+dy[j];
            if(a[xx][yy]<=b[i].num)
            {
                merge(id(xx,yy),id(b[i].x,b[i].y));
            }
        }
        if(b[i].num!=b[i+1].num)
        {
            for(int j=i;;j--)
            {
                if(b[j].num!=b[i].num)
                {
                    break;
                }
                if(f[b[j].x][b[j].y])
                {
                    int f=find(id(b[j].x,b[j].y));
                    if(!s[f])
                    {
                        s[f]=1;
                        ans++;
                    }
                }
            }
        }
    }
    printf("%d",ans);
    return 0;
}
